import{_ as e,o as t,c as o,e as i}from"./app-4924a84b.js";const r={},n=i('<h1 id="glossary-术语" tabindex="-1"><a class="header-anchor" href="#glossary-术语" aria-hidden="true">#</a> Glossary 术语</h1><h2 id="common-acronyms-常用缩写" tabindex="-1"><a class="header-anchor" href="#common-acronyms-常用缩写" aria-hidden="true">#</a> Common Acronyms 常用缩写</h2><ul><li>AC: actual cost 实际成本</li><li>BAC: budget at completion 完工预算</li><li>CCB: change control board 变更控制委员会</li><li>CFD: cumulative flow diagram 累积流量图</li><li>COQ: cost of quality 质量成本</li><li>CPAF: cost plus award fee 成本+奖励费用</li><li>CPFF: cost plus fixed fee 成本+固定费用</li><li>CPI: cost performance index 成本绩效指数</li><li>CPIF: const plus incentive fee 成本+激励费用</li><li>CPM: critical path method 关键路径法</li><li>CV: cost variance 成本偏差</li><li>DoD: definition of done 完成的定义</li><li>EAC: estimate at completion 完工估算</li><li>EEF: enterprise environmental factors 事业环境因素</li><li>EMV: expected monetary value 预期货币价值</li><li>ETC: estimate to complete 完工尚需估算</li><li>EV: earned value 挣值</li><li>EVA: earned value analysis 挣值分析</li><li>FFP: firm fixed price 固定总价</li><li>FPEPA: fixed price with economic price adjustment 总价+经济价格调整</li><li>FPIF: fixed price incentive fee 总价+激励费用</li><li>IDIQ: indefinite delivery indefinite quantity 不确定交付和数量</li><li>LCA: life cycle assessment 生命周期评估</li><li>MVP: minimum viable product 最小可行产品</li><li>NPS: Net Promotor Score 净推荐值</li><li>OBS: organizational breakdown structure 组织分解结构</li><li>OPA: organizational process assets 组织过程资产</li><li>PMB: performance measurement baseline 绩效测量基准</li><li>PMBOK: Project Management Body of Knowledge 项目管理知识体系</li><li>PMO: project management office 项目管理办公室</li><li>PV: planned value 计划价值</li><li>RAM: responsibility assignment matrix 责任分配矩阵</li><li>RBS: risk breakdown structure 风险分解结构</li><li>SOW: statement of work 工作说明书</li><li>SPI: schedule performance index 进度绩效指数</li><li>SV: schedule variance 进度偏差</li><li>SWOT: strengths, weaknesses, opportunities and threats 优势、劣势、机会与威胁</li><li>T&amp;M: time and materials contract 工料合同</li><li>VAC: variance at completion 完工偏差</li><li>VDO: value delivery office 价值交付办公室</li><li>WBS: work breakdown structure 工作分解结构</li></ul><h2 id="definitions" tabindex="-1"><a class="header-anchor" href="#definitions" aria-hidden="true">#</a> Definitions</h2><ul><li><strong>Acceptance Criteria</strong>. A set of conditions that is required to be met before deliverables are accepted.<br><strong>验收标准</strong>：可交付物通过验收前必须满足的一系列条件。</li><li><strong>Accuracy</strong>. Within the quality management system, accuracy is an assessment of correctness.<br><strong>准确度</strong>：在质量管理体系中，“准确度”是指对正确程度的评估。</li><li><strong>Activity List</strong>. A documented tabulation of schedule activities that shows the activity description, activity identifier, and sufficiently detailed scope of work description so project team members understand what work is to be performed.<br><strong>活动清单</strong>：一份记录进度活动的表格，包含活动描述、活动标识及足够详细的工作范围描述，以便项目团队成员了解所需执行的工作。</li><li><strong>Actual Cost(AC)</strong>. The realized cost incurred for the work performed on an activity during a specific time period.<br><strong>实际成本（AC）</strong>：在特定时间段内，因执行项目活动而实际发生的成本。</li><li><strong>Adaptive Approach</strong>. A development approach in which the requirements are subject to a high level of uncertainty and volatility and are like to change throughout the project.<br><strong>适应型方法</strong>：一种开发方法，当需求面临高度的不确定性和易变性的影响，并且可能在整个项目期间发生变化时，这种方法非常有用。</li><li><strong>Affinity Diagram</strong>. A diagram that shows large numbers of ideas classified into groups for review and analysis.<br><strong>亲和图</strong>：一种展示对大量创意进行分组，以便进一步审查和分析的图形。</li><li><strong>Affinity Grouping</strong>. The process of classifying items into similar categories or collections on the basic of their likeness.<br><strong>亲和分组</strong>：根据相似程度将各项内容归入类似类别或组合的过程。</li><li><strong>Agile</strong>. A term used to describe a mindset of values and principles as set forth in the Agile Manifesto.<br><strong>敏捷</strong>：这个术语用来描述《敏捷宣言》中提出的一种有关价值和原则的思维方式。</li><li><strong>Alternatives Analysis</strong>. A method used to evaluate identified options in order to select the options or approaches to use to perform the work of the project.<br><strong>备选方案分析</strong>：一种用于评估已识别选项的方法，以便选择哪种选项或方法来执行项目工作。</li><li><strong>Ambiguity</strong>. A state of being unclear, having difficulty in identifying the cause of events, or having multiple options from which to choose.<br><strong>模糊性</strong>：不清晰的状态，难以识别事件的起因，或者有多个从中选择的选项。</li><li><strong>Analogous Estimating</strong>. A method for estimating the duration or cost of an activity or a project using historical data from a similar activity or project.<br><strong>类比估算</strong>：使用相似活动或项目的历史数据，来估算当前活动或项目的持续时间或成本的方法。</li><li><strong>Artifact</strong>. A template, document, output, or project deliverable.<br><strong>工件</strong>：模板、文档、输出或项目交付物。</li><li><strong>Assumption</strong>. A factor in the planning process that is considered to be true, real, or certain, without proof or demonstration.<br><strong>假设条件</strong>：在规划过程中没有证据或证明就被认为正确、真实或确定的因素。</li><li><strong>Assumption and Constraint Analysis</strong>. An assessment that ensures assumptions and constraints are integrated into the project plans and documents, and that there is consistency among them.<br><strong>假设条件和制约因素分析</strong>：旨在确保将假设条件和制约因素整合进项目计划和文件，并且使它们之间保持一致性的评估。</li><li><strong>Assumption Log</strong>. A project document used to record all assumptions and constraints throughout the project.<br><strong>假设日志</strong>：在整个项目期间用来记录所有假设条件和制约因素的项目文件。</li><li><strong>Authority</strong>: The right to apply project resources, expend funds, make decisions, or give approvals.<br><strong>职权</strong>：使用项目资源、花费资金、做出决策或给予批准的权力。</li><li><strong>Backlog</strong>: An ordered list of work to be done.<br><strong>待办事项列表</strong>:待完成工作的有序列表。</li><li><strong>Backlog Refinement</strong>: Progressive elaboration of the content in the backlog and (re)prioritization of it to identify the work that can be accomplished in an upcoming iteration.<br><strong>待办事项列表细化</strong>：待办事项列表中内容的渐进明细，并重新确定其中各事项的优先级，以识别可在即将到 来的迭代完成的工作。</li><li><strong>Baseline</strong>: The approved version of a work product, used as a basis for comparison to actual results.<br><strong>基准</strong>：经过批准的工作产品的版本，用作与实际结果进行比较的依据。</li><li><strong>Basis of Estimates</strong>:Supporting documentation outlining the details used in establishing project estimates such as assumptions, constraints, level of detail, ranges, and confidence levels.<br><strong>估算依据</strong>：概述用来建立项目估算细节的支持性文件，如假设条件、制约因素、详细程度、估算区间和置信水平。</li><li><strong>Benchmarking</strong>:The comparison of actual or planned products, processes, and practices to those of comparable organizations to identify best practices, generate ideas for improvement, and provide a basis for measuring performance.<br><strong>标杆对照</strong>：将实际或计划的产品、流程和做法，与其他可比组织的做法进行比较，以便识别最佳实践，形成改进意见，并为绩效考核提供依据。</li><li><strong>Benefits Management Plan</strong>:The documented explanation defining the processes for creating, maximizing, and sustaining the benefits provided by a project or program.<br><strong>收益管理计划</strong>：对创建、最大化和维持项目或项目集收益过程的定义进行书面化说明。</li><li><strong>Bid Documents</strong>: All documents used to solicit information, quotations, or proposals from prospective sellers.<br><strong>招标文件</strong>：用于从潜在卖方征求信息、报价或建议书的所有文件。</li><li><strong>Bidder Conference</strong>: The meetings with prospective sellers prior to the preparation of a bid or proposal to ensure all prospective vendors have a clear and common understanding of the procurement. Also known as contractor conferences, vendor conferences, or pre-bid conferences.<br><strong>投标人会议</strong>：在准备投标或建议书之前，与潜在卖方举行的会议，以便确保所有潜在卖方对本次采购都有清楚且一致的理解。也称承包商会议、供应商会议或投标前会议。</li><li><strong>Blocker</strong>: See <code>impediment</code>.<br><strong>障碍</strong>：参见“障碍因素”。</li><li><strong>Budget</strong>: The approved estimate for the project or any work breakdown structure (WBS) component or any schedule activity.<br><strong>预算</strong>：经批准的对整个项目、任一工作分解结构 (WBS) 组件或任一进度活动所做的估算。</li><li><strong>Budget at Completion (BAC)</strong>: The sum of all budgets established for the work to be performed.<br><strong>完工预算 (BAC)</strong>：为要执行的工作所确立的全部预算的总和。</li><li><strong>Burn Chart</strong>: A graphical representation of the work remaining in a timebox or the work completed toward the release of a product or project deliverable.<br><strong>燃烧图</strong>：时间盒中剩余工作，或者为发布产品或项目可交付物已完成工作的图形化表示。</li><li><strong>Business Case</strong>: A value proposition for a proposed project that may include financial and nonfinancial benefits.<br><strong>商业论证</strong>：针对可能包含财务和非财务收益所提议项目的价值主张。</li><li><strong>Business Model Canvas</strong>: A one-page, visual summary that describes the value proposition, infrastructure, customers, and finances. These are often used in Lean Startup situations.<br><strong>商业模式画布</strong>：一页纸的可视化摘要，描述了价值主张、基础设施、客户和财务状况。它们通常用于精益创业情境。</li><li><strong>Business Value</strong>: The net quantifiable benefit derived from a business endeavor that may be tangible, intangible, or both.<br><strong>商业价值</strong>：源自商业活动的可量化净收益，可能是有形的，也可能是无形的，或者二者皆有。</li></ul>',5),s=[n];function a(l,c){return t(),o("div",null,s)}const d=e(r,[["render",a],["__file","02.Glossary.html.vue"]]);export{d as default};
